// Puppeteer-based Synthetics canary bundled for the syn-nodejs-puppeteer runtime.
// AWS wraps this module; the entry point must be exposed as `handler` on
// `exports` and receive nothing — it uses the runtime's synthetics helpers.

const synthetics = require("Synthetics");
const log = require("SyntheticsLogger");

const targets = [
  { url: "https://showcase.dram-soc.org/",              mustContain: "tokyo zero" },
  { url: "https://showcase.dram-soc.org/work/",         mustContain: "PSG" },
  { url: "https://showcase.dram-soc.org/architecture/", mustContain: "cloudfront" },
];

const check = async () => {
  const page = await synthetics.getPage();

  for (const t of targets) {
    const started = Date.now();
    const response = await page.goto(t.url, {
      waitUntil: "domcontentloaded",
      timeout: 15000,
    });
    const took = Date.now() - started;

    if (!response || response.status() !== 200) {
      throw new Error(
        `${t.url} returned ${response ? response.status() : "no response"}`
      );
    }

    const body = await page.content();
    if (!body.includes(t.mustContain)) {
      throw new Error(`${t.url} missing expected marker: ${t.mustContain}`);
    }

    if (took > 8000) {
      throw new Error(`${t.url} slow: ${took}ms`);
    }

    log.info(`${t.url} OK — ${took}ms`);
    await synthetics.takeScreenshot(
      t.url.split("/").filter(Boolean).pop() || "home",
      "loaded"
    );
  }
};

exports.handler = async () => {
  return await check();
};
